#!/usr/bin/env python3
import sys, re, html, json, urllib.request

PORT = sys.argv[1] if len(sys.argv) > 1 else "3400"
BASE = f"http://127.0.0.1:{PORT}"

def get(path, timeout=120):
    with urllib.request.urlopen(BASE + path, timeout=timeout) as r:
        return r.read().decode("utf-8", "replace")

def textify(s):
    s = re.sub("<[^>]+>", " ", s)
    return html.unescape(re.sub(r"\s+", " ", s)).strip()

idx_html = get("/")
pairs = re.findall(r'/thy/trace/(\d+)/overview/help">([^<]+)<', idx_html)
results = {}
for idx, name in pairs:
    try:
        raw = get(f"/thy/trace/{idx}/main/rules")
    except Exception as e:
        results[name] = f"<ERR {e}>"
        continue
    # response is JSON {"html": "..."} sometimes; unwrap if so
    body = raw
    try:
        j = json.loads(raw)
        if isinstance(j, dict) and "html" in j:
            body = j["html"]
    except Exception:
        pass
    low = body.lower()
    i = low.find("injective instances")
    if i < 0:
        results[name] = "<no injective header>"
        continue
    # take text after the header up to the next section header
    tail = body[i+len("injective instances"):]
    ttail = textify(tail)
    # cut at "Multiset Rewriting Rules"
    cut = ttail.lower().find("multiset rewriting rules")
    if cut >= 0:
        ttail = ttail[:cut].strip()
    results[name] = ttail

for name in sorted(results):
    print(f"{name}\t=>\t{results[name]}")

#!/usr/bin/env python3
# Scrape the injective line for the single theory served on PORT.
import sys, re, html, json, urllib.request
PORT = sys.argv[1]
BASE = f"http://127.0.0.1:{PORT}"

def get(path, timeout=180):
    with urllib.request.urlopen(BASE + path, timeout=timeout) as r:
        return r.read().decode("utf-8", "replace")

def textify(s):
    return html.unescape(re.sub(r"\s+", " ", re.sub("<[^>]+>", " ", s))).strip()

idx = get("/")
# support both trace and equiv (diff) theories
ms = re.findall(r'/thy/(trace|equiv)/(\d+)/overview/help', idx)
if not ms:
    print("NO_THEORY_LINK"); sys.exit(0)
out = []
for kind, i in ms:
    try:
        raw = get(f"/thy/{kind}/{i}/main/rules")
    except Exception as e:
        out.append(f"[{kind}{i}:ERR {e}]"); continue
    body = raw
    try:
        j = json.loads(raw)
        if isinstance(j, dict) and "html" in j:
            body = j["html"]
    except Exception:
        pass
    low = body.lower()
    k = low.find("injective instances")
    if k < 0:
        out.append(f"[{kind}{i}:no-header]"); continue
    tail = textify(body[k + len("injective instances"):])
    cut = tail.lower().find("multiset rewriting rules")
    if cut >= 0:
        tail = tail[:cut].strip()
    out.append(tail)
print(" || ".join(out))

//! Clean-room detection of protocol facts with *injective instances*.
//!
//! Behaviour characterised entirely from black-box oracle observations of the
//! tamarin-prover web UI ("Fact Symbols with Injective Instances" on the
//! `/main/rules` page); see workspace/BEHAVIOR.md. No tamarin-prover source was
//! consulted.
//!
//! A linear fact tag `t` is injective iff:
//!   (I)  some rule contains `t` in *both* its premises and its conclusions
//!        (a state loop), and
//!   (II) in *every* rule, the multiset of `t`-conclusion first-arguments minus
//!        (by term equality) the multiset of `t`-premise first-arguments is a
//!        sub-multiset of the fresh names generated by that rule's `Fr` premises
//!        — i.e. every newly-created instance carries a distinct freshly
//!        generated name in its first argument.

pub mod ast;

use ast::{Fact, Rule, SortHint, Term, VarSpec};
use std::collections::BTreeSet;

/// A fact tag: the fact symbol name together with its arity. Only linear
/// (non-persistent) tags can be injective.
pub type FactTag = (String, usize);

/// Compute the set of protocol fact tags that have injective instances.
///
/// `rules` are the theory's multiset-rewriting rules (each rule's `premises`
/// and `conclusions` are inspected; `actions`, `variants`, `left_right` and
/// `embedded_restrictions` are irrelevant to the decision). For diff theories
/// the caller supplies the concrete left/right rule set.
pub fn injective_fact_instances(rules: &[Rule]) -> BTreeSet<FactTag> {
    // (I) Candidate tags: linear, arity >= 1, occurring in both premises and
    //     conclusions of one rule.
    let mut candidates: BTreeSet<FactTag> = BTreeSet::new();
    for r in rules {
        let prem_tags: BTreeSet<FactTag> = r
            .premises
            .iter()
            .filter(|f| is_linear_keyed(f))
            .map(tag_of)
            .collect();
        for f in &r.conclusions {
            if is_linear_keyed(f) {
                let t = tag_of(f);
                if prem_tags.contains(&t) {
                    candidates.insert(t);
                }
            }
        }
    }

    // (II) Keep only candidates for which every rule creates new instances
    //      conservatively (net-new first-args are distinct freshly-generated
    //      names).
    candidates
        .into_iter()
        .filter(|t| rules.iter().all(|r| rule_conservative_for(r, t)))
        .collect()
}

/// A fact can carry an injective key only if it is linear and has a first
/// argument.
fn is_linear_keyed(f: &Fact) -> bool {
    !f.persistent && !f.args.is_empty()
}

fn tag_of(f: &Fact) -> FactTag {
    (f.name.clone(), f.args.len())
}

fn has_tag(f: &Fact, t: &FactTag) -> bool {
    !f.persistent && f.name == t.0 && f.args.len() == t.1
}

/// Check condition (II) for tag `t` on a single rule.
fn rule_conservative_for(r: &Rule, t: &FactTag) -> bool {
    // First-argument multisets for tag `t`.
    let prem_keys: Vec<&Term> = r
        .premises
        .iter()
        .filter(|f| has_tag(f, t))
        .map(|f| &f.args[0])
        .collect();
    let conc_keys: Vec<&Term> = r
        .conclusions
        .iter()
        .filter(|f| has_tag(f, t))
        .map(|f| &f.args[0])
        .collect();

    // Fresh names generated by this rule (one per `Fr(v)` premise).
    let mut fresh_pool: Vec<&VarSpec> = r
        .premises
        .iter()
        .filter(|f| is_fresh_fact(f))
        .filter_map(|f| match &f.args[0] {
            Term::Var(v) => Some(v),
            _ => None,
        })
        .collect();

    // net_new = conc_keys minus one matching prem_key each (carried instances).
    let mut prem_pool = prem_keys;
    for c in &conc_keys {
        if let Some(pos) = prem_pool.iter().position(|p| *p == *c) {
            prem_pool.remove(pos); // this conclusion instance was carried through
        } else {
            // Newly created: its first argument must be a distinct fresh name.
            match c {
                Term::Var(v) if v.sort == SortHint::Fresh => {
                    match fresh_pool.iter().position(|fv| **fv == *v) {
                        Some(pos) => {
                            fresh_pool.remove(pos);
                        }
                        None => return false, // fresh-sorted but not Fr-generated (or reused)
                    }
                }
                _ => return false, // first argument is not a freshly generated name
            }
        }
    }
    true
}

/// The built-in `Fr` fact that generates a fresh name.
fn is_fresh_fact(f: &Fact) -> bool {
    !f.persistent && f.name == "Fr" && f.args.len() == 1
}

//! Validation harness. Reads a compact description of a theory's rules on stdin
//! and prints the injective fact tags (one `name/arity` per line, sorted).
//!
//! This binary only *reconstructs* `Rule`/`Fact`/`Term` values so the real
//! library function can be exercised on rules parsed from the oracle's own
//! normalized rule pretty-print. It carries no injectivity logic.
//!
//! Input grammar (one token stream per line):
//!   RULE                 -- start a new rule
//!   P <fact>             -- a premise fact
//!   C <fact>             -- a conclusion fact
//! where <fact> = [!]name arg1 arg2 ...   (whitespace separated, no inner spaces)
//! and a token starting with '~' is a Fresh variable; anything else is treated
//! as a non-variable literal (only first-argument freshness / equality matter).

use injfacts_clean::ast::{Fact, Rule, SortHint, Term, VarSpec};
use injfacts_clean::injective_fact_instances;
use std::io::{self, Read};

fn token_to_term(tok: &str) -> Term {
    if let Some(rest) = tok.strip_prefix('~') {
        Term::Var(VarSpec {
            name: rest.to_string(),
            idx: 0,
            sort: SortHint::Fresh,
            typ: None,
        })
    } else {
        Term::PubLit(tok.to_string())
    }
}

fn parse_fact(fields: &[&str]) -> Fact {
    let raw = fields[0];
    let (persistent, name) = match raw.strip_prefix('!') {
        Some(n) => (true, n.to_string()),
        None => (false, raw.to_string()),
    };
    let args = fields[1..].iter().map(|t| token_to_term(t)).collect();
    Fact {
        persistent,
        name,
        args,
        annotations: vec![],
    }
}

fn empty_rule() -> Rule {
    Rule {
        name: String::new(),
        modulo: None,
        attributes: vec![],
        let_block: vec![],
        premises: vec![],
        actions: vec![],
        conclusions: vec![],
        embedded_restrictions: vec![],
        variants: vec![],
        left_right: None,
    }
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();

    let mut rules: Vec<Rule> = Vec::new();
    let mut cur: Option<Rule> = None;
    for line in input.lines() {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        let fields: Vec<&str> = line.split_whitespace().collect();
        match fields[0] {
            "RULE" => {
                if let Some(r) = cur.take() {
                    rules.push(r);
                }
                cur = Some(empty_rule());
            }
            "P" => {
                if let Some(r) = cur.as_mut() {
                    r.premises.push(parse_fact(&fields[1..]));
                }
            }
            "C" => {
                if let Some(r) = cur.as_mut() {
                    r.conclusions.push(parse_fact(&fields[1..]));
                }
            }
            _ => {}
        }
    }
    if let Some(r) = cur.take() {
        rules.push(r);
    }

    let result = injective_fact_instances(&rules);
    for (name, arity) in result {
        println!("{}/{}", name, arity);
    }
}

//! Probe fixtures: every minimal probe theory from the characterisation
