fn p03_persistent() {
    // Fr->!CC(~id); !CC(~id)->Out  => None (persistent)
    let rs = vec![
        rule(vec![fr(fresh("id"))], vec![per("CC", vec![fresh("id")])]),
        rule(vec![per("CC", vec![fresh("id")])], vec![lin("Out", vec![fresh("id")])]),
    ];
    assert_eq!(injective_fact_instances(&rs), none());
}

