#!/usr/bin/env python3
# Fetch /main/rules for the single theory on PORT. Save raw body (all theories
# on the server) to OUTFILE. Print the injective line(s).
import sys, re, html, json, urllib.request
PORT, OUT = sys.argv[1], sys.argv[2]
BASE = f"http://127.0.0.1:{PORT}"

def get(path, timeout=180):
    with urllib.request.urlopen(BASE + path, timeout=timeout) as r:
        return r.read().decode("utf-8", "replace")

def textify(s):
    return html.unescape(re.sub(r"\s+", " ", re.sub("<[^>]+>", " ", s))).strip()

idx = get("/")
ms = re.findall(r'/thy/(trace|equiv)/(\d+)/overview/help', idx)
if not ms:
    print("NO_THEORY_LINK"); sys.exit(0)
bodies = []
inj = []
for kind, i in ms:
    raw = get(f"/thy/{kind}/{i}/main/rules")
    body = raw
    try:
        j = json.loads(raw)
        if isinstance(j, dict) and "html" in j:
            body = j["html"]
    except Exception:
        pass
    bodies.append(f"<<<THEORY {kind} {i}>>>\n" + body)
    low = body.lower(); k = low.find("injective instances")
    if k < 0:
        inj.append("<no-header>")
    else:
        tail = textify(body[k+len("injective instances"):])
        cut = tail.lower().find("multiset rewriting rules")
        if cut >= 0: tail = tail[:cut].strip()
        inj.append(tail)
with open(OUT, "w", encoding="utf-8") as f:
    f.write("\n".join(bodies))
print(" || ".join(inj))

#!/usr/bin/env python3
# End-to-end corpus validation.
# For each saved /main/rules body: parse the pretty-printed MSR rules into the
# compact format, run the injfacts binary, and compare its output to the oracle's
# "Fact Symbols with Injective Instances" line on the same page.
import sys, os, re, html, json, subprocess, glob

SP = "/tmp/claude-1000/-home-kamilner-tamarin-rs/57f8e1bc-d495-4b36-93c0-033347d5034a/scratchpad"
BIN = "/home/kamilner/tamarin-cleanroom/injective/workspace/injfacts-clean/target/release/injfacts"
HTMLDIR = os.path.join(SP, "corpus_html")

def strip_tags(s):
    return html.unescape(re.sub("<[^>]+>", "", s))

def split_top(s, opens="(<", closes=")>"):
    """split by top-level commas respecting () and <> nesting."""
    out, depth, cur = [], 0, ""
    for ch in s:
        if ch in opens: depth += 1; cur += ch
        elif ch in closes: depth -= 1; cur += ch
        elif ch == "," and depth == 0:
            out.append(cur); cur = ""
        else: cur += ch
    if cur.strip() or out:
        out.append(cur)
    return [x.strip() for x in out if x.strip() != ""]

def find_groups(block):
    """return list of contents of top-level [...] groups (brackets don't nest in terms)."""
    groups, i, n = [], 0, len(block)
    while i < n:
        if block[i] == "[":
            j = block.find("]", i)
            if j < 0: break
            groups.append((i, j, block[i+1:j]))
            i = j + 1
        else:
            i += 1
    return groups

def parse_fact(fstr):
    fstr = fstr.strip()
    if not fstr:
        return None
    persistent = fstr.startswith("!")
    if persistent:
        fstr = fstr[1:].strip()
    m = re.match(r"^([A-Za-z_][A-Za-z0-9_]*)", fstr)
    if not m:
        return None
    name = m.group(1)
    rest = fstr[m.end():].strip()
    args = []
    if rest.startswith("("):
        # outermost paren group
        depth, k = 0, 0
        for k, ch in enumerate(rest):
            if ch == "(": depth += 1
            elif ch == ")":
                depth -= 1
                if depth == 0:
                    break
        inner = rest[1:k]
        args = split_top(inner)
    return (persistent, name, args)

def emit_fact(tag, fact):
    persistent, name, args = fact
    toks = [("!" if persistent else "") + name]
    for a in args:
        toks.append(re.sub(r"\s+", "", a))  # strip inner spaces so tokens are whitespace-free
    return tag + " " + " ".join(toks)

def parse_rules(section_text):
    txt = strip_tags(section_text)
    # cut to the MSR rules section
    i = txt.find("Multiset Rewriting Rules")
    if i >= 0:
        txt = txt[i + len("Multiset Rewriting Rules"):]
    # remove /* ... */ comments
    txt = re.sub(r"/\*.*?\*/", " ", txt, flags=re.S)
    # split into rule blocks at 'rule ('
    parts = re.split(r"\brule\s*\(", txt)
    lines = []
    for part in parts[1:]:
        # part starts after 'rule (' ; block ends at next 'rule (' (already split) or end
        # remove the "modulo X) name:" header up to first '['
        b = part
        br = b.find("[")
        if br < 0:
            continue
        block = b[br:]
        groups = find_groups(block)
        if not groups:
            continue
        prem = groups[0][2]
        # decide whether actions present: '--[' between prem end and next group
        after_prem = block[groups[0][1]+1:]
        arrow_region = after_prem[:after_prem.find("[")] if "[" in after_prem else after_prem
        has_actions = "--[" in arrow_region
        if has_actions:
            concl = groups[2][2] if len(groups) >= 3 else ""
        else:
            concl = groups[1][2] if len(groups) >= 2 else ""
        lines.append("RULE")
        for fs in split_top(prem):
            f = parse_fact(fs)
            if f: lines.append(emit_fact("P", f))
        for fs in split_top(concl):
            f = parse_fact(fs)
            if f: lines.append(emit_fact("C", f))
    return "\n".join(lines)

def oracle_names(inj_line):
    inj_line = inj_line.strip()
    if inj_line in ("None", "", "<no-header>"):
        return set()
    names = set()
    for item in inj_line.split(","):
        item = item.strip()
        m = re.match(r"^([A-Za-z_][A-Za-z0-9_]*)", item)
        if m:
            names.add(m.group(1))
    return names

def run_binary(compact):
    p = subprocess.run([BIN], input=compact, capture_output=True, text=True)
    names = set()
    for ln in p.stdout.splitlines():
        ln = ln.strip()
        if ln:
            names.add(ln.split("/")[0])
    return names

def main():
    files = sorted(glob.glob(os.path.join(HTMLDIR, "*.html")))
    total = ok = mism = 0
    mismatches = []
    for f in files:
        uid = os.path.basename(f)[:-5]
        body = open(f, encoding="utf-8", errors="replace").read()
        # split into theory sections
        secs = re.split(r"<<<THEORY [a-z]+ \d+>>>", body)
        secs = [s for s in secs if s.strip()]
        for si, sec in enumerate(secs):
            low = sec.lower(); k = low.find("injective instances")
            if k < 0:
                continue
            tail = html.unescape(re.sub(r"\s+", " ", re.sub("<[^>]+>", " ", sec[k+len("injective instances"):]))).strip()
            cut = tail.lower().find("multiset rewriting rules")
            if cut >= 0: tail = tail[:cut].strip()
            expected = oracle_names(tail)
            compact = parse_rules(sec)
            got = run_binary(compact)
            total += 1
            tagid = uid + ("" if len(secs) == 1 else f"#{si}")
            if got == expected:
                ok += 1
            else:
                mism += 1
                mismatches.append((tagid, sorted(expected), sorted(got)))
    print(f"theories/sections compared: {total}  match: {ok}  MISMATCH: {mism}")
    for tid, exp, got in mismatches:
        print(f"  MISMATCH {tid}\n     oracle: {exp}\n     mine  : {got}")

if __name__ == "__main__":
    main()
